var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정신을 잃은 상태에서도, 어째서인지 저희를 거부하시더라고요.","JPN":"気を失った状態でも、どうしてか我々を拒否されていましたね。","ENG":"But even when you were unconscious, you were somehow refusing us.","TWN":"即使是在昏迷的狀態下，不知道為什麼，你也拒絕了我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"결국 제물을 전부 소진했는데도 연명 조치에 그쳤답니다.","JPN":"結果生贄を全部使っても、延命措置に留まってしまいました。","ENG":"Eventually, we were able to sustain your life after depleting all our resources.","TWN":"最後我們用光了所有祭物，也只是停在了為你勉強續命上。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니야……","JPN":"違う……","ENG":"No...","TWN":"不是的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"고민했어요. 오직 레지나 님을 위해서.","JPN":"悩みました。レジーナ様のためだけを思って。","ENG":"We thought hard. All for your well-being, Miss Regina.","TWN":"我們苦惱了很久，為了蕾佳娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니야……!","JPN":"違う……！","ENG":"NO...!","TWN":"不……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"결국 <color=#ffd34c>심연에 계신 분</color>이라면 레지나 님도 거부하지 않으리라고 판단했죠.","JPN":"結局、<color=#ffd34c>深淵にいらっしゃる方</color>なら、レジーナ様も拒否されないだろうと判断しました。","ENG":"Ultimately, we decided that even you would not be able to refuse if it is <color=#ffd34c>Him in the Gulf</color>.","TWN":"最後我們判斷，如果是<color=#ffd34c>深淵中的那位</color>，應該也不會拒絕蕾佳娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이번에는 특히 준비에 공을 들였어요. 그 분은 우둔한 주제에 까탈스러우셔서.","JPN":"今回は特に念入りに準備しました。あの方は鈍いくせに気難しいので。","ENG":"We worked hard to prepare for this. The Idiot is rather picky.","TWN":"這次我們特意在準備方面下了功夫。因為那位存在雖然有些盲目，但同時又很挑剔。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"질문에 답해 드릴게요. 합중국을 공격한 건 제 지시가 맞아요.","JPN":"質問にお答えしましょう。合衆国を攻撃したのは確かに我々が指示したことです。","ENG":"We'll answer your question. Yes, we ordered the attack on the States.","TWN":"我們來回答你的問題。攻擊合眾國是我們的指示沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론 혹시 나타날지 모를 방해꾼들의 이목을 잠시 돌려 두기 위해서랍니다.","JPN":"もちろん、現れるかもしれない邪魔者の目をしばらく逸らせるためです。","ENG":"However, it was to divert the attention of any intruders who might appear here.","TWN":"當然是為了暫時轉移可能會出來礙事之人的注意力。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"전쟁을 할 의도는 아니었어요. 그랬다면 다른 저희를 보내지도 않았겠죠.","JPN":"戦争を起こすつもりはありませんでした。あったなら、別の我々を向かわせることもなかったでしょう。","ENG":"We did not want war. If we did, we wouldn't have sent another \\"us\\".","TWN":"我們的意圖不是發動戰爭。如果是那樣，我們就不會派出其他分身了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 듣고 계신가요?","JPN":"レジーナ様、聞いていますか？","ENG":"Miss Regina, are you listening?","TWN":"蕾佳娜，你在聽嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"최대한 쉽게 풀어 말씀드렸다고 생각했는데, 아직 부족한가 보네요.","JPN":"できるだけわかりやすく説明したつもりでしたが、まだ足りないようですね。","ENG":"We're doing everything we can to make it as simple as possible. But perhaps it isn't simple enough.","TWN":"我們覺得已經盡可能簡單地為你解釋了，但是好像還不夠。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"아직 어린 나이요. 전부 자기 때문에 벌어진 일이란 사실을 받아들이기 힘들겠지.","JPN":"まだ幼い。すべてが自分のせいで起こったという事実が受け入れがたいのだろう。","ENG":"She's still young. It'll be hard for her to accept the fact that this all happened because of her.","TWN":"她年紀還小。應該很難接受一切都是因自己而起，這種現實吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"의식은 어떻소?","JPN":"儀式はどうだ？","ENG":"How is the ritual going?","TWN":"儀式怎麼樣了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"순조롭습니다. 이대로라면 무척이나 값진 결과를 얻을 수 있겠어요.","JPN":"順調です。このままいくと、大変貴重な結果を得ることができるでしょう。","ENG":"It is going smoothly. At this rate, we will obtain an extremely valuable outcome.","TWN":"很順利。照這樣下去，應該能得到非常有價值的成果。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"균열의 규모도 충분하군요. 의식은 곧 완성될 것입니다.","JPN":"亀裂の規模も十分です。もうすぐ儀式が完成されます。","ENG":"The scale of the dimensional rift is sufficient. The ritual will soon be complete.","TWN":"裂縫的規模也夠了。儀式就要完成了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"축하드리오, 학회장. 잠시 후에 공들인 성과를 확인할 수 있겠군.","JPN":"おめでとう、学会長。しばらくしたら念を入れた成果を確認することができるだろう。","ENG":"Congratulations, President. We will soon enjoy the results of our efforts.","TWN":"恭喜你，學會長。稍後就能確認你嘔心瀝血的成果了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하이드리히 소장도 충분히 수고해 주셨어요.","JPN":"ハイドリヒ所長も十分頑張ってくださいました。","ENG":"As to you, Chief Heydrich. You did well.","TWN":"海德里希所長，你也辛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네퀴티아, 당신 역시.","JPN":"ネキティア、あなたも。","ENG":"And Nequitia, as for you.","TWN":"莉奎蒂亞，你也辛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"호연에 감사합니다. 이후에도 학회는 멘탈 프린팅 기술의 완성에 적극적으로 협조해 드릴 거예요.","JPN":"好演に感謝します。これからも学会はメンタル・プリンティング技術の完成に積極的にご協力いたします。","ENG":"Thank you for your outstanding performance. After all of this is completed, the Society will fully support the completion of the Mental Printing technology.","TWN":"謝謝你的精彩演示。以後學會也會積極配合你完成智力複印技術。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"왕의 비호는 쉽게 얻는 것이 아니죠. 호평해 주셔서 감사드립니다.","JPN":"王の庇護は簡単に得られるものではございません。ご好評、感謝いたします。","ENG":"A lord's protection is not obtained so easily. Thank you for your kind words.","TWN":"王的庇護不是輕易就能得到的，謝謝你的好評。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"왜 그래, 루나? 아까부터 박자가 계속 어긋나지 않아?","JPN":"どうしたの？　ルナ。さっきから拍子がずれてるけど？","ENG":"What's wrong, Luna? Your tempo continues to be off-beat.","TWN":"你怎麼了，露娜？從剛才開始節拍就一直在出錯？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"목에 바람 구멍이라도 나고 싶어서 그럴까?","JPN":"喉に風穴でも開けられたいのかしら。","ENG":"Are you wanting another hole made in your throat?","TWN":"你是想在脖子上開幾個洞嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그, 그렇진 않아. 그런 건 아니고…….","JPN":"そ、そうじゃない。そうじゃなくて……","ENG":"N-no, it’s not that...","TWN":"不…不是的，不是那樣的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에델, 다들 한 몫 챙기는데 나는?","JPN":"エデル、みんなご褒美もらってるけど、アタシは？","ENG":"Edel, everyone's got a piece, so what about me?","TWN":"艾瑟兒，大家都有回報，那我呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후훗, 물론 리벳에게도 합당한 대가를 드려야죠. 항상 저희를 위해 고생해 주는 분인걸요.","JPN":"ふふっ、もちろんリベットにもそれ相応の対価を差し上げます。いつも我々のために頑張ってくださってますから。","ENG":"Hah hah, of course. You will be paid handsomely, Rivet. You always work hard for us.","TWN":"呵呵，我當然也要給里維適當的報酬。你可是一直在幫助我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"오오, 합당한 대가라. 귀가 솔깃한 말이야, 정말.","JPN":"おお、相応の対価。アタシの大好きな言葉だ。","ENG":"Ooh! Handsomely, eh? Now that's what I like to hear!","TWN":"噢噢，適當的報酬，這話真的很動聽。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"너무 걱정하지 마세요, 레지나 님.","JPN":"あまりご心配なさらないでください、レジーナ様。","ENG":"Don't be scared, Miss Regina.","TWN":"你別太擔心了，蕾佳娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"새로운 존재로 거듭나는 과정은 고통스럽지 않답니다.","JPN":"新しい存在に生まれ変わる過程は苦しくありません。","ENG":"The process of becoming a new being is not painful at all.","TWN":"變成新存在的過程，其實並不痛苦。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"오히려 아주 황홀한 경험이 될 거예요. 이 몸이 기억하고 있듯이.","JPN":"むしろ、とても素晴らしい経験になりますよ。この身体が覚えているように。","ENG":"In fact, the contrary is true. You will experience ecstasy. Just how this body still remembers the feeling.","TWN":"相反，你會覺得很恍惚，就像這具身軀記憶中的那樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델…….","JPN":"エデル……","ENG":"Edel...","TWN":"艾瑟兒……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"나는, 나는 당신을……","JPN":"私は、私はあなたを……","ENG":"I... I...","TWN":"我，我把你……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"알아요. 친구로 받아들여 주셨죠.","JPN":"わかっています。友達として受け入れてくださいましたね。","ENG":"We know. You accepted us as your friend.","TWN":"我知道，你把我們當成朋友。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래서예요. 저는 레지나 님을 잃을 수 없어요.","JPN":"だからです。我々はレジーナ様を奪われるわけにはいきません。","ENG":"That is why... we cannot lose you, Miss Regina.","TWN":"所以，我們才不能失去蕾佳娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"다른 마왕들에게도, 신에게도.","JPN":"他の魔王にも、神にも。","ENG":"Not to any Demon Lord, not to any god...","TWN":"不能把你輸給其他魔王，輸給神。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"시간에게마저도.","JPN":"時間にさえも。","ENG":"And even time.","TWN":"又或者是輸給時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 체념해 버렸네.","JPN":"ふふっ、あきらめちゃったわね。","ENG":"Fuu fuu, she's given up.","TWN":"呵呵，死心了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"귀여운 인간이야. 마왕님이 집착할 만큼 대단한 구석이 있는지는 모르겠지만.","JPN":"可愛い人間だわ。魔王様が執着するほど、すごいところがあるかはわからないけど。","ENG":"Such a cute little human. But I'm not sure what it is about her that has the Demon Lord so enamored.","TWN":"這個人類確實很可愛。就是不知道有沒有值得魔王大人如此執著的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"헛소리 말고 연주에나 집중하지 그래?","JPN":"無駄話しないで、演奏に集中したら？","ENG":"Stop chitchatting and focus on playing your cello, will you?","TWN":"別說沒用的，專心演奏好嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"곧 있으면 클라이맥스야. 집중이 흐트러질수록 그 마왕님이랑 척질 확률이 높아질걸?","JPN":"もうすぐクライマックスよ。集中が乱れるほど、その魔王様に嫌われる確率が高くなるわ。","ENG":"The crescendo is coming soon. You mess this up and your chances of fighting the Demon Lord will be certain.","TWN":"馬上就到高潮部分了。如果注意力不集中，就有可能得罪那個魔王吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"셰나, 내 연주는 늘 정확하단다. 지휘자님께서 돌아오신 이상 잔소리는 하지 말아 줄래?","JPN":"シェナ、私の演奏はいつでも正確なの。マエストロがお戻りになった以上、小言はやめてくれない？","ENG":"Shena, my playing is always accurate. With Chief Conductor back, will you please stop your nagging?","TWN":"世娜，我的演奏一直很準確。指揮家已經回來了，你能別再嘮叨了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄, 그렇다기엔 아까부터 네 소리가 너무 날카로워졌는데.","JPN":"どうかな、それにしてはさっきからあなたの音が鋭くなってるわよ。","ENG":"Oh really? Because to me, your playing has become too sharp for that.","TWN":"這個嘛，雖然是這樣，但是從剛才開始你的聲音就變得太刺耳了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"응? 그건 왠지 공기가……","JPN":"うん？　それはどうしてか空気が……","ENG":"Hmm? The air...","TWN":"嗯？不知道怎麼回事，感覺空氣……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"입김이 나오는군. 냉방 시설 문제는 아닌 것 같은데.","JPN":"息が白くなってきたな。冷房施設の問題ではなさそうだが。","ENG":"I can see my breath. But there seems to be nothing wrong with the air conditioner.","TWN":"有哈氣了。好像不是製冷設施的問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"잠깐, 이 발소리는……","JPN":"待って、この足音は……","ENG":"Wait. Those footsteps...","TWN":"等等，這腳步聲……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어머나, 초대 받지 않은 손님이 한 분 더 계셨네요.","JPN":"あら、招かれざる客がもう一人いたのですね。","ENG":"Oh my, it appears we have another uninvited guest.","TWN":"哎唷，還有一位不請自來的客人呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저 괴물은…… 부학회장님을 쫓던……?","JPN":"あの化け物は……副学会長様を追ってた……？","ENG":"That monster... Isn't it the same one that chased the Vice President...?","TWN":"那個怪物是……追趕副學會長的……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레. 지나.</color>","JPN":"<color=#ff3636>レ、ジーナ。</color>","ENG":"<color=#ff3636>Re. Gina.</color>","TWN":"<color=#ff3636>蕾佳·娜。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>여. 기 있. 었구나.</color>","JPN":"<color=#ff3636>コ、コニイ、タンダ。</color>","ENG":"<color=#ff3636>Th.ere you. Are.</color>","TWN":"<color=#ff3636>原·來·在這·裡。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"전 인원, 무기를 들어라.","JPN":"全員、武器を持て。","ENG":"Everyone, raise your weapons.","TWN":"全體人員，舉起武器。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"외견을 봐선 1408호에서 학살을 일으켰다던 그 괴물이군.","JPN":"外見からすると、1408号で虐殺を起こしたというあの怪物だな。","ENG":"It looks exactly like the monster that caused the massacre in Room 1408.","TWN":"從外表來看，應該是在1408號製造屠殺的那個怪物。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"어떻게 하시겠소, 학회장.","JPN":"どうなさるおつもりか、学会長。","ENG":"Your orders, President.","TWN":"怎麼辦，學會長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……레지나 님을 노리게 내버려 둘 수는 없죠.","JPN":"……レジーナ様を狙うものを許すわけにはいきません。","ENG":"...We cannot let it go after Miss Regina.","TWN":"……當然不能任由它覬覦蕾佳娜了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"잘됐네요. 마침 허기가 지던 참이었답니다.","JPN":"ちょうどよかったです。お腹が空いたと感じていたところでしたから。","ENG":"However, excellent timing. We were about to get hungry.","TWN":"來得正好，我們剛好餓了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};